// Calculate budget allocations based on grant amount and program focus
const request = $('Budget Request').first().json.body;
const templateItems = $('Get Budget Template').all().map(i => i.json);

const grantAmount = parseFloat(request.grantAmount) || 0;
const programFocus = (request.programFocus || 'balanced').toLowerCase();
const adminCap = parseFloat(request.adminCap) || 100; // Default no cap

// Adjust percentages based on program focus
const focusMultipliers = {
  youth: { youth: 1.3, senior: 0.5, shared: 1.0, admin: 1.0 },
  senior: { youth: 0.5, senior: 1.3, shared: 1.0, admin: 1.0 },
  balanced: { youth: 1.0, senior: 1.0, shared: 1.0, admin: 1.0 }
};

const multipliers = focusMultipliers[programFocus] || focusMultipliers.balanced;

// Calculate raw allocations
let lineItems = templateItems.map(item => {
  const basePercent = parseFloat(item.default_percent) || 0;
  const programArea = (item.program_area || 'shared').toLowerCase();
  const category = (item.category || 'direct').toLowerCase();

  // Apply focus multiplier
  const multiplier = multipliers[programArea] || 1.0;
  const adjustedPercent = basePercent * multiplier;

  return {
    lineItem: item.line_item,
    category: category,
    programArea: programArea,
    basePercent: basePercent,
    adjustedPercent: adjustedPercent,
    description: item.description || ''
  };
});

// Normalize percentages to 100%
const totalPercent = lineItems.reduce((sum, item) => sum + item.adjustedPercent, 0);
lineItems = lineItems.map(item => ({
  ...item,
  normalizedPercent: (item.adjustedPercent / totalPercent) * 100,
  amount: Math.round((item.adjustedPercent / totalPercent) * grantAmount)
}));

// Calculate category totals
const categoryTotals = {
  personnel: { amount: 0, percent: 0 },
  direct: { amount: 0, percent: 0 },
  indirect: { amount: 0, percent: 0 }
};

let adminTotal = 0;
let adminPercent = 0;

for (const item of lineItems) {
  const cat = item.category === 'personnel' ? 'personnel' : 
              item.category === 'indirect' ? 'indirect' : 'direct';
  categoryTotals[cat].amount += item.amount;
  categoryTotals[cat].percent += item.normalizedPercent;

  // Track admin costs (indirect + admin program area)
  if (item.category === 'indirect' || item.programArea === 'admin') {
    adminTotal += item.amount;
    adminPercent += item.normalizedPercent;
  }
}

return [{
  json: {
    grantAmount: grantAmount,
    programFocus: programFocus,
    funderName: request.funderName || 'Unknown Funder',
    grantPurpose: request.grantPurpose || 'general program support',
    adminCap: adminCap,
    lineItems: lineItems,
    categoryTotals: categoryTotals,
    adminTotal: adminTotal,
    adminPercent: Math.round(adminPercent * 10) / 10,
    needsAdjustment: adminPercent > adminCap
  }
}];

// Apply funder restrictions (admin cost caps)
const data = $input.first().json;
const warnings = [];

let lineItems = [...data.lineItems];
let adminPercent = data.adminPercent;
const adminCap = data.adminCap;

// If admin costs exceed cap, we need to reallocate
if (data.needsAdjustment && adminCap < 100) {
  const excessPercent = adminPercent - adminCap;
  warnings.push(`Admin costs reduced from ${adminPercent.toFixed(1)}% to ${adminCap}% per funder requirements`);

  // Find admin/indirect items and reduce proportionally
  const adminItems = lineItems.filter(i => 
    i.category === 'indirect' || i.programArea === 'admin'
  );
  const nonAdminItems = lineItems.filter(i => 
    i.category !== 'indirect' && i.programArea !== 'admin'
  );

  // Calculate reduction factor for admin items
  const reductionFactor = adminCap / adminPercent;

  // Reduce admin items
  let totalReduced = 0;
  adminItems.forEach(item => {
    const oldAmount = item.amount;
    item.amount = Math.round(item.amount * reductionFactor);
    item.normalizedPercent = item.normalizedPercent * reductionFactor;
    totalReduced += (oldAmount - item.amount);
  });

  // Redistribute to direct program costs proportionally
  const directItems = nonAdminItems.filter(i => i.category === 'direct' || i.category === 'personnel');
  const directTotal = directItems.reduce((sum, i) => sum + i.amount, 0);

  directItems.forEach(item => {
    const proportion = item.amount / directTotal;
    const bonus = Math.round(totalReduced * proportion);
    item.amount += bonus;
    item.normalizedPercent = (item.amount / data.grantAmount) * 100;
  });

  lineItems = [...adminItems, ...nonAdminItems];
  adminPercent = adminCap;
}

// Recalculate category totals
const categoryTotals = {
  personnel: { amount: 0, percent: 0 },
  direct: { amount: 0, percent: 0 },
  indirect: { amount: 0, percent: 0 }
};

for (const item of lineItems) {
  const cat = item.category === 'personnel' ? 'personnel' : 
              item.category === 'indirect' ? 'indirect' : 'direct';
  categoryTotals[cat].amount += item.amount;
  categoryTotals[cat].percent += item.normalizedPercent;
}

// Round percentages
Object.keys(categoryTotals).forEach(key => {
  categoryTotals[key].percent = Math.round(categoryTotals[key].percent * 10) / 10;
});

return [{
  json: {
    ...data,
    lineItems: lineItems,
    categoryTotals: categoryTotals,
    adminPercent: Math.round(adminPercent * 10) / 10,
    warnings: warnings
  }
}];

