// Format final budget output
const budgetData = $('Apply Funder Restrictions').first().json;
const aiResponse = $input.first().json;

const narrative = aiResponse.message?.content || aiResponse.text || '';

// Build formatted line items for display
const formattedLineItems = budgetData.lineItems.map(item => ({
  lineItem: item.lineItem,
  category: item.category,
  programArea: item.programArea,
  amount: item.amount,
  amountFormatted: `$${item.amount.toLocaleString()}`,
  percent: Math.round(item.normalizedPercent * 10) / 10,
  description: item.description
}));

// Sort by category then amount
formattedLineItems.sort((a, b) => {
  const catOrder = { personnel: 1, direct: 2, indirect: 3 };
  if (catOrder[a.category] !== catOrder[b.category]) {
    return catOrder[a.category] - catOrder[b.category];
  }
  return b.amount - a.amount;
});

// Build summary table as markdown
let markdownTable = `## Budget Summary: ${budgetData.funderName}\n\n`;
markdownTable += `**Grant Amount:** $${budgetData.grantAmount.toLocaleString()}\n`;
markdownTable += `**Program Focus:** ${budgetData.programFocus}\n`;
markdownTable += `**Purpose:** ${budgetData.grantPurpose}\n\n`;

markdownTable += `### Category Totals\n`;
markdownTable += `| Category | Amount | Percent |\n`;
markdownTable += `|----------|--------|---------|\n`;
markdownTable += `| Personnel | $${budgetData.categoryTotals.personnel.amount.toLocaleString()} | ${budgetData.categoryTotals.personnel.percent}% |\n`;
markdownTable += `| Direct Program | $${budgetData.categoryTotals.direct.amount.toLocaleString()} | ${budgetData.categoryTotals.direct.percent}% |\n`;
markdownTable += `| Administrative | $${budgetData.categoryTotals.indirect.amount.toLocaleString()} | ${budgetData.categoryTotals.indirect.percent}% |\n`;
markdownTable += `| **TOTAL** | **$${budgetData.grantAmount.toLocaleString()}** | **100%** |\n\n`;

markdownTable += `### Line Item Detail\n`;
markdownTable += `| Line Item | Category | Amount | % | Description |\n`;
markdownTable += `|-----------|----------|--------|---|-------------|\n`;
for (const item of formattedLineItems) {
  markdownTable += `| ${item.lineItem} | ${item.category} | ${item.amountFormatted} | ${item.percent}% | ${item.description} |\n`;
}

markdownTable += `\n### Budget Narrative\n\n${narrative}\n`;

if (budgetData.warnings && budgetData.warnings.length > 0) {
  markdownTable += `\n### ⚠️ Adjustments Made\n`;
  for (const warning of budgetData.warnings) {
    markdownTable += `- ${warning}\n`;
  }
}

markdownTable += `\n---\n*Generated: ${new Date().toISOString()}*`;

return [{
  json: {
    success: true,
    grantAmount: budgetData.grantAmount,
    funderName: budgetData.funderName,
    programFocus: budgetData.programFocus,
    categoryTotals: budgetData.categoryTotals,
    adminPercent: budgetData.adminPercent,
    lineItems: formattedLineItems,
    narrative: narrative,
    warnings: budgetData.warnings || [],
    markdownBudget: markdownTable
  }
}];

// Calculate budget allocations based on grant amount and program focus
const request = $('Budget Request1').first().json.body;

// --------------------------------------------------
// ✅ Parse amount (always string)
// --------------------------------------------------

const rawAmount = (request.grantAmount || '').toString();

// Extract all dollar values like $15,000
const matches = rawAmount.match(/\$[\d,]+/g) || [];

// Helper to clean "$2,000,000" -> 2000000
const cleanMoney = (str) =>
  parseFloat(str.replace(/[^0-9.]/g, '')) || 0;

let amountType = 'none';
let grantAmount = 0;
let grantAmountMin = 0;
let grantAmountMax = 0;
let amountNote = '';

if (matches.length === 1) {
  amountType = 'exact';
  grantAmount = cleanMoney(matches[0]);
  amountNote = `Exact amount: $${grantAmount.toLocaleString()}`;
}

if (matches.length >= 2) {
  amountType = 'range';
  grantAmountMin = cleanMoney(matches[0]);
  grantAmountMax = cleanMoney(matches[1]);
  grantAmount = grantAmountMin; // conservative choice
  amountNote = `Range: $${grantAmountMin.toLocaleString()} - $${grantAmountMax.toLocaleString()} (using minimum)`;
}

if (matches.length === 0) {
  amountType = 'none';
  grantAmount = 0;
  amountNote = 'No grant amount specified - budget percentages only';
}

const hasAmount = matches.length > 0;

// --------------------------------------------------
// Parse Plane [Budget] issues into template items
// --------------------------------------------------

const response = $('Get Budget Template1').first().json;
const allIssues = response.results || response || [];
const issueList = Array.isArray(allIssues) ? allIssues : [];

const templateItems = [];

for (const issue of issueList) {
  const name = issue.name || '';
  const match = name.match(/\[Budget\]\s*\S+\s*-\s*(.+)/);
  if (!match) continue;

  const desc = issue.description_html || '';

  const getField = (label) => {
    const m = desc.match(new RegExp(label + ':</strong>\\s*([^<]+)'));
    return m ? m[1].trim() : '';
  };

  templateItems.push({
    line_item: match[1].trim(),
    category: getField('Category'),
    program_area: getField('Program Area'),
    default_percent: parseFloat(getField('Default Percent')) || 0,
    description: getField('Description')
  });
}

// --------------------------------------------------
// Program focus logic
// --------------------------------------------------

const programFocus = (request.programFocus || 'balanced').toLowerCase();
const adminCap = parseFloat(request.adminCap) || 100;

const focusMultipliers = {
  youth: { youth: 1.3, senior: 0.5, shared: 1.0, admin: 1.0 },
  senior: { youth: 0.5, senior: 1.3, shared: 1.0, admin: 1.0 },
  balanced: { youth: 1.0, senior: 1.0, shared: 1.0, admin: 1.0 }
};

const multipliers = focusMultipliers[programFocus] || focusMultipliers.balanced;

// --------------------------------------------------
// Calculate allocations
// --------------------------------------------------

let lineItems = templateItems.map(item => {
  const basePercent = parseFloat(item.default_percent) || 0;
  const programArea = (item.program_area || 'shared').toLowerCase();
  const category = (item.category || 'direct').toLowerCase();

  const multiplier = multipliers[programArea] || 1.0;
  const adjustedPercent = basePercent * multiplier;

  return {
    lineItem: item.line_item,
    category,
    programArea,
    basePercent,
    adjustedPercent,
    description: item.description || ''
  };
});

const totalPercent = lineItems.reduce((sum, item) => sum + item.adjustedPercent, 0);

lineItems = lineItems.map(item => ({
  ...item,
  normalizedPercent: totalPercent > 0 ? (item.adjustedPercent / totalPercent) * 100 : 0,
  amount: totalPercent > 0 ? Math.round((item.adjustedPercent / totalPercent) * grantAmount) : 0
}));

// --------------------------------------------------
// Category totals
// --------------------------------------------------

const categoryTotals = {
  personnel: { amount: 0, percent: 0 },
  direct: { amount: 0, percent: 0 },
  indirect: { amount: 0, percent: 0 }
};

let adminTotal = 0;
let adminPercent = 0;

for (const item of lineItems) {
  const cat =
    item.category === 'personnel'
      ? 'personnel'
      : item.category === 'indirect'
      ? 'indirect'
      : 'direct';

  categoryTotals[cat].amount += item.amount;
  categoryTotals[cat].percent += item.normalizedPercent;

  if (item.category === 'indirect' || item.programArea === 'admin') {
    adminTotal += item.amount;
    adminPercent += item.normalizedPercent;
  }
}

// --------------------------------------------------
// Return result
// --------------------------------------------------

return [{
  json: {
    grantAmount,
    amountType,
    grantAmountMin,
    grantAmountMax,
    amountNote,
    hasAmount,

    programFocus,
    funderName: request.funderName || 'Unknown Funder',
    grantPurpose: request.grantPurpose || 'general program support',
    adminCap,

    lineItems,
    categoryTotals,
    adminTotal,
    adminPercent: Math.round(adminPercent * 10) / 10,
    needsAdjustment: adminPercent > adminCap
  }
}];

